{"type":"user","message":{"role":"user","content":[{"tool_use_id":"tooluse_YrN37pbhO8WIP35sf5r17r","type":"tool_result","content":"1\t#!/usr/bin/env python3\n2\t\"\"\"\n3\tPlatform Breakout Pattern Detection for ChiNext Stocks\n4\tFinds stocks that broke out of a narrow trading range with volume confirmation\n5\t\"\"\"\n6\t\n7\timport akshare as ak\n8\timport pandas as pd\n9\tfrom datetime import datetime, timedelta\n10\t\n11\tdef get_chinext_stocks():\n12\t    \"\"\"Get list of ChiNext (创业板) stock codes\"\"\"\n13\t    try:\n14\t        stock_info = ak.stock_info_a_code_name()\n15\t        chinext = stock_info[stock_info['code'].str.startswith('3')]\n16\t        return chinext['code'].tolist()\n17\t    except Exception as e:\n18\t        print(f\"Error getting ChiNext stocks: {e}\")\n19\t        return []\n20\t\n21\tdef get_stock_data(code, end_date, days=15):\n22\t    \"\"\"Get historical K-line data for a stock\"\"\"\n23\t    try:\n24\t        # Calculate start date (need more days to ensure we get 15 trading days)\n25\t        start_date = (datetime.strptime(end_date, '%Y%m%d') - timedelta(days=30)).strftime('%Y%m%d')\n26\t\n27\t        df = ak.stock_zh_a_hist(symbol=code, period=\"daily\",\n28\t                                start_date=start_date, end_date=end_date, adjust=\"\")\n29\t\n30\t        if df is None or len(df) < days:\n31\t            return None\n32\t\n33\t        # Get the last 15 trading days\n34\t        df = df.tail(days).reset_index(drop=True)\n35\t\n36\t        if len(df) < days:\n37\t            return None\n38\t\n39\t        return df\n40\t    except Exception as e:\n41\t        return None\n42\t\n43\tdef check_breakout_pattern(df):\n44\t    \"\"\"\n45\t    Check if stock meets platform breakout criteria:\n46\t    1. First 10 days: narrow range (high-low < 5% of low)\n47\t    2. Last 5 days: at least 3 days close above first 10 days' high\n48\t    3. Breakout day volume > 1.5x average volume of first 10 days\n49\t    \"\"\"\n50\t    if len(